package dev.sargunv.mobilitydata.utils

import kotlinx.coroutines.CancellationException

/**
 * Calls the specified suspending [block] and wraps its outcome in a [Result].
 *
 * Unlike [kotlin.runCatching], this can be used with suspending code, and it rethrows
 * [CancellationException] so that coroutine cancellation is not accidentally swallowed.
 *
 * @return [Result.success] with the block's value, or [Result.failure] wrapping any other thrown
 * [Throwable].
 */
public suspend fun <R> suspendRunCatching(block: suspend () -> R): Result<R> =
  try {
    Result.success(block())
  } catch (cancellation: CancellationException) {
    throw cancellation
  } catch (exception: Throwable) {
    Result.failure(exception)
  }

